// Code generated by togo (test) - extend with your own cases.
package rest

import (
	"context"
	"os"
	"testing"

	"github.com/danielgtaylor/huma/v2/humatest"
	"github.com/togo-framework/togo"

	"github.com/saudi-ventures/saudi-ventures/internal/app"
)

// TestCapabilitySourceAPI exercises the capability_sources endpoints. Set
// TEST_DATABASE_URL (a migrated DB) to run it; skipped otherwise.
func TestCapabilitySourceAPI(t *testing.T) {
	if os.Getenv("TEST_DATABASE_URL") == "" {
		t.Skip("set TEST_DATABASE_URL to run CapabilitySource API tests")
	}
	os.Setenv("DATABASE_URL", os.Getenv("TEST_DATABASE_URL"))

	k := togo.New()
	a := app.New(context.Background(), k)
	defer k.Close()
	if a.SQLDB == nil {
		t.Skip("database unavailable")
	}

	_, api := humatest.New(t)
	RegisterCapabilitySourceRoutes(api, a)

	if resp := api.Get("/api/capability_sources"); resp.Code != 200 {
		t.Fatalf("list capability_sources: expected 200, got %d", resp.Code)
	}
}
